-- Products 81-100: Clams, crayfish, crab sticks, shrimp, halibut, scallops, etc.
INSERT INTO products (name_zh, name_en, brand, category, description_zh, description_en, price, unit, image_url, features, is_featured, additional_info) VALUES

('蒜蓉粉絲蛤蜊', 'Garlic Vermicelli Clams', '顏師傅', 'prepared', '精選新鮮蛤蜊搭配細嫩粉絲，以蒜蓉醬汁調味，只需加熱即可享用，鮮甜湯汁拌飯拌麵都美味。', 'Fresh clams paired with glass noodles in a savory garlic sauce. Heat and serve — the briny sweet broth is perfect over rice or noodles.', 280, '380g/pack',
'/cdn/images/products/81-01.jpg', '["蒜蓉風味","即食蛤蜊","附粉絲","鮮甜湯汁"]', 0,
'zh: 蒜蓉粉絲蛤蜊，顏師傅品牌，每包380g，蛤蜊搭配粉絲蒜蓉醬汁。en: Garlic Vermicelli Clams by Yan Master, 380g per pack, clams with glass noodles in garlic sauce.'),

('醬汁小龍蝦', 'Seasoned Crayfish', '顏師傅', 'shellfish', '選用肥美小龍蝦，以秘製香辣醬汁醃製入味，開袋即食，麻辣鮮香，是聚餐下酒的人氣美食。', 'Plump crayfish marinated in a house spicy-savory sauce. Ready to eat out of the bag — bold, fragrant, and perfect with a cold drink.', 320, '500g/pack',
'/cdn/images/products/82-01.jpg', '["醬汁入味","即食小龍蝦","麻辣鮮香","聚餐首選"]', 0,
'zh: 醬汁小龍蝦，顏師傅品牌，500g，秘製醬汁醃製即食小龍蝦。en: Seasoned Crayfish by Yan Master, 500g, ready-to-eat crayfish in house spicy sauce.'),

('蟹肉棒', 'Crab Sticks', '元家', 'prepared', '以優質魚漿製成的蟹肉棒，口感Q彈，蟹香濃郁，適合火鍋、關東煮、沙拉等多種料理，老少咸宜。', 'Crab sticks made from premium fish paste — springy texture with rich crab flavor. Great for hot pot, oden, salads, and more.', 120, '200g/pack',
'/cdn/images/products/83-01.jpg', '["Q彈魚漿","蟹香風味","火鍋必備","多用途"]', 0,
'zh: 蟹肉棒，元家品牌，200g，魚漿製蟹風味棒，適合火鍋關東煮。en: Crab Sticks by Yuan Jia, 200g, fish paste crab-flavor sticks for hot pot and oden.'),

('蝦仁年糕', 'Shrimp Rice Cake', '顏師傅', 'prepared', '鮮嫩蝦仁搭配軟糯年糕，以鮮美醬汁調味，口感豐富有層次，加熱即食，適合當點心或主食。', 'Tender shrimp paired with chewy rice cakes in a savory sauce. Heat and enjoy — great as a snack or a light meal.', 220, '300g/pack',
'/cdn/images/products/84-01.jpg', '["蝦仁年糕","軟糯口感","即食點心","鮮美醬汁"]', 0,
'zh: 蝦仁年糕，顏師傅品牌，300g，蝦仁配軟糯年糕即食調理包。en: Shrimp Rice Cake by Yan Master, 300g, shrimp with chewy rice cakes, heat and serve.'),

('冷凍青花菜', 'Frozen Broccoli', '元家', 'prepared', '嚴選優質青花菜，急速冷凍鎖住營養與色澤，方便搭配各式料理，補充膳食纖維與維生素C，健康美味兼顧。', 'Premium broccoli blanched and flash-frozen to lock in nutrients and color. Versatile, healthy, and easy to add to any meal.', 80, '500g/bag',
'/cdn/images/products/85-01.jpg', '["急速冷凍","保留營養","方便料理","健康蔬菜"]', 0,
'zh: 冷凍青花菜，元家品牌，500g，急速冷凍保留青花菜營養。en: Frozen Broccoli by Yuan Jia, 500g, flash-frozen to preserve nutrients and color.'),

('活凍小干貝', 'Live-Frozen Bay Scallop', '元家', 'shellfish', '精選小型帆立貝活體急凍，保留貝柱鮮甜原味，體積小巧適合快炒、煮粥、做湯，鮮味十足，用途廣泛。', 'Small live-frozen scallops that preserve the natural sweetness of the adductor muscle. Compact and versatile — great for stir-fry, congee, or soups.', 380, '500g/pack',
'/cdn/images/products/86-01.jpg', '["活凍鮮甜","小型干貝","快炒煮粥","用途廣泛"]', 0,
'zh: 活凍小干貝，元家品牌，500g，小型帆立貝活體急凍，鮮甜多用途。en: Live-Frozen Bay Scallop by Yuan Jia, 500g, small scallops live-frozen for maximum sweetness.'),

('海鮮調理包', 'Seafood Meal Kit', '元家', 'prepared', '精選多種海鮮食材組合，附專屬醬汁包，簡單加熱即可完成一道豐盛海鮮料理，適合忙碌家庭快速上桌。', 'A curated mix of premium seafood with house sauce included. Quick and easy — just heat and serve for a restaurant-quality seafood dish at home.', 450, '600g/pack',
'/cdn/images/products/87-01.jpg', '["多種海鮮","附醬汁包","簡單料理","家庭首選"]', 0,
'zh: 海鮮調理包，元家品牌，600g，多種海鮮附醬汁，即時料理包。en: Seafood Meal Kit by Yuan Jia, 600g, assorted seafood with sauce, quick-cook meal kit.'),

('炸海鮮點心', 'Fried Seafood Snacks', '顏師傅', 'prepared', '多種海鮮製成的酥炸點心組合，外皮酥脆、內餡鮮美，氣炸鍋或油炸均可，適合派對聚會分享。', 'An assortment of crispy fried seafood snacks — crunchy outside, juicy and flavorful inside. Air-fry or deep-fry. Perfect for parties and sharing platters.', 280, '400g/pack',
'/cdn/images/products/88-01.jpg', '["酥炸海鮮","外脆內嫩","氣炸鍋適用","派對點心"]', 0,
'zh: 炸海鮮點心，顏師傅品牌，400g，多種海鮮酥炸點心，氣炸鍋適用。en: Fried Seafood Snacks by Yan Master, 400g, assorted crispy seafood snacks, air-fryer friendly.'),

('火鍋料（綜合）', 'Hot Pot Ingredients Mix', '元家', 'prepared', '精選魚板、蟹棒、蝦餃、花枝丸等多種火鍋料組合，一包搞定火鍋配料，Q彈鮮美，全家大小都愛吃。', 'A generous assortment of fish cakes, crab sticks, shrimp dumplings, squid balls, and more. Everything you need for a delicious hot pot in one pack.', 320, '600g/pack',
'/cdn/images/products/89-01.jpg', '["綜合火鍋料","多種口味","Q彈鮮美","全家適用"]', 1,
'zh: 綜合火鍋料，元家品牌，600g，魚板蟹棒蝦餃花枝丸多種組合。en: Hot Pot Ingredients Mix by Yuan Jia, 600g, assorted fish cakes, crab sticks, shrimp dumplings, squid balls.'),

('鮑魚切片', 'Sliced Abalone', '品元堂', 'shellfish', '頂級乾鮑魚切片，以傳統工藝精製，每片薄而均勻，鮮香醇厚，用於粥品、紅燒或直接泡發食用，滋補養生。', 'Premium dried abalone sliced to uniform thickness. Rich, briny, and deeply savory — use in congee, braised dishes, or rehydrate and serve as is. A prized tonic ingredient.', 1980, '100g/box',
'/cdn/images/products/90-01.jpg', '["頂級乾鮑","薄切均勻","滋補養生","傳統工藝"]', 1,
'zh: 鮑魚切片，品元堂品牌，100g，頂級乾鮑魚薄切，傳統工藝精製，適合粥品紅燒。en: Sliced Abalone by Pin Yuan Tang, 100g box, premium dried abalone sliced thin, traditional craftsmanship, for congee or braised dishes.'),

('海鮮沙拉', 'Seafood Salad', '顏師傅', 'prepared', '精選蟹肉、蝦仁、花枝拌製而成的冷盤沙拉，以清爽醬汁調味，開袋即食，適合作為前菜或輕食主餐。', 'A refreshing chilled salad of crab meat, shrimp, and squid tossed in a light dressing. Ready to eat — serve as an appetizer or a light lunch.', 180, '200g/pack',
'/cdn/images/products/91-01.jpg', '["冷盤海鮮","開袋即食","清爽醬汁","前菜輕食"]', 0,
'zh: 海鮮沙拉，顏師傅品牌，200g，蟹肉蝦仁花枝冷盤沙拉，開袋即食。en: Seafood Salad by Yan Master, 200g, chilled crab, shrimp, and squid salad, ready to eat.'),

('桂花人蔘燉品', 'Osmanthus Ginseng Tonic Soup', '品元堂', 'prepared', '精選人蔘搭配桂花，以傳統慢燉工藝製成，甘甜溫潤，補氣養神，是秋冬滋補的養生珍品。', 'Korean ginseng slow-simmered with osmanthus flowers in the traditional way. Gently sweet and warming — a prized tonic for energy and wellness in autumn and winter.', 680, '250ml/bottle',
'/cdn/images/products/92-01.jpg', '["人蔘桂花","慢燉養生","補氣溫潤","秋冬滋補"]', 0,
'zh: 桂花人蔘燉品，品元堂品牌，250ml，人蔘搭配桂花慢燉，補氣養神。en: Osmanthus Ginseng Tonic Soup by Pin Yuan Tang, 250ml, ginseng simmered with osmanthus, warming and nourishing.'),

('海鮮風味香腸', 'Seafood-Flavor Sausage', '顏師傅', 'prepared', '以海鮮精華調製的特色香腸，帶有淡淡海鮮香氣，口感紮實，適合燒烤、煎炒或切片拼盤，風味獨特。', 'Sausages infused with seafood essence — a subtle briny aroma with a firm, satisfying bite. Great grilled, pan-fried, or sliced for a charcuterie platter.', 220, '300g/pack',
'/cdn/images/products/93-01.jpg', '["海鮮風味","特色香腸","燒烤煎炒","口感紮實"]', 0,
'zh: 海鮮風味香腸，顏師傅品牌，300g，海鮮精華調製香腸，燒烤煎炒均可。en: Seafood-Flavor Sausage by Yan Master, 300g, sausages infused with seafood essence, grill or pan-fry.'),

('白蝦（帶頭）', 'Whole White Shrimp with Head', '元家', 'shrimp', '新鮮白蝦帶頭完整保存，急速冷凍鎖住鮮甜，蝦頭富含鮮味精華，適合清蒸、鹽焗、蒜蓉料理，鮮味滿溢。', 'Whole white shrimp with heads on, flash-frozen to lock in sweetness. The heads add deep umami. Steam, salt-bake, or cook with garlic for maximum flavor.', 380, '600g/pack',
'/cdn/images/products/94-01.jpg', '["帶頭白蝦","鮮味精華","急速冷凍","清蒸鹽焗"]', 0,
'zh: 白蝦（帶頭），元家品牌，600g，帶頭完整白蝦急速冷凍，鮮味足。en: Whole White Shrimp with Head by Yuan Jia, 600g, head-on white shrimp flash-frozen for maximum sweetness.'),

('大比目魚（整尾）', 'Whole Halibut', '元家', 'fish', '來自北太平洋的大型比目魚，整尾冷凍保鮮，肉質潔白細嫩，富含優質蛋白，適合切片清蒸、煎烤或紅燒。', 'Large Pacific halibut frozen whole. Pure white flesh, mild and delicate. Slice for steaming, pan-sear, or braise — an elegant centerpiece for any seafood meal.', 1580, 'per fish (~3kg)',
'/cdn/images/products/95-01.jpg', '["整尾比目魚","北太平洋","肉質潔白","多種料理"]', 0,
'zh: 大比目魚（整尾），元家品牌，北太平洋大型比目魚整尾冷凍，約3kg。en: Whole Halibut by Yuan Jia, whole frozen Pacific halibut approx. 3kg, white delicate flesh.'),

('大比目魚頭', 'Halibut Head', '元家', 'fish', '比目魚頭部位，膠質豐富，肉質鮮嫩，價格實惠，適合紅燒、清蒸或煮湯，膠質溶入湯中鮮美無比。', 'Halibut head — rich in collagen with tender, flavorful meat at a great value. Braise, steam, or make soup; the collagen melts into the broth for a silky, umami-rich finish.', 320, '800g/piece',
'/cdn/images/products/96-01.jpg', '["比目魚頭","豐富膠質","紅燒清蒸","價格實惠"]', 0,
'zh: 大比目魚頭，元家品牌，約800g，膠質豐富適合紅燒清蒸煮湯。en: Halibut Head by Yuan Jia, approx. 800g, collagen-rich, ideal for braising, steaming, or soup.'),

('獅爪干貝（特大）', 'Giant Lion''s Paw Scallop', '品元堂', 'shellfish', '頂級特大型獅爪干貝，肉柱飽滿碩大，鮮甜醇厚，以傳統日曬工藝精製，是煮粥、蒸蛋、紅燒的絕佳食材，稀有珍貴。', 'Exceptionally large lion''s paw scallops sun-dried in the traditional way. Dense, meaty, and intensely sweet — prized for congee, steamed egg, and braised dishes. A rare premium ingredient.', 2880, '150g/box',
'/cdn/images/products/97-01.jpg', '["特大干貝","獅爪品種","傳統日曬","稀有珍貴"]', 1,
'zh: 獅爪干貝（特大），品元堂品牌，150g，特大型獅爪干貝，傳統日曬工藝，稀有珍貴。en: Giant Lion''s Paw Scallop by Pin Yuan Tang, 150g box, extra-large sun-dried scallop, rare premium ingredient.'),

('蛤蜊肉（去殼）', 'Shelled Clam Meat', '元家', 'shellfish', '新鮮蛤蜊去殼取肉，急速冷凍保鮮，使用方便免去去殼麻煩，適合快炒、煮湯、做義大利麵、煮粥等多種料理。', 'Fresh clam meat shelled and flash-frozen for convenience. No shucking needed — drop straight into stir-fries, chowders, pasta, or congee.', 220, '300g/pack',
'/cdn/images/products/98-01.jpg', '["去殼蛤蜊","方便使用","急速冷凍","多種料理"]', 0,
'zh: 蛤蜊肉（去殼），元家品牌，300g，去殼蛤蜊肉急速冷凍，方便料理。en: Shelled Clam Meat by Yuan Jia, 300g, shucked clam meat flash-frozen, convenient for cooking.'),

('熟凍干貝（小）', 'Cooked Frozen Scallop Small', '元家', 'shellfish', '小型干貝以熟凍方式保鮮，解凍即可食用，鮮甜Q彈，適合炒飯、壽司、涼拌或直接食用，用途廣泛。', 'Small scallops cooked and frozen at peak freshness. Thaw and eat — sweet, tender, and springy. Great for fried rice, sushi, salads, or straight as a snack.', 280, '400g/pack',
'/cdn/images/products/99-01.jpg', '["熟凍干貝","解凍即食","鮮甜Q彈","多種用途"]', 0,
'zh: 熟凍干貝（小），元家品牌，400g，小型干貝熟凍保鮮，解凍即食。en: Cooked Frozen Scallop Small by Yuan Jia, 400g, small scallops cooked and frozen, thaw and serve.'),

('鮭魚鰭邊肉', 'Salmon Engawa (Fin Meat)', '元家', 'fish', '鮭魚背鰭旁稀有部位，油脂豐厚、口感獨特，每條魚僅能取得少量，是壽司迷必嚐的夢幻食材，極致脂香令人難忘。', 'The prized strip of fatty meat alongside the salmon dorsal fin. Rare — only a small amount per fish. Deeply marbled, buttery, and intensely flavored. A must for sushi lovers.', 680, '200g/pack',
'/cdn/images/products/100-01.jpg', '["稀有部位","油脂豐厚","壽司首選","脂香迷人"]', 1,
'zh: 鮭魚鰭邊肉（エンガワ），元家品牌，200g，鮭魚背鰭旁稀有部位，油脂豐厚，壽司用途。en: Salmon Engawa (Fin Meat) by Yuan Jia, 200g, rare fatty strip from salmon dorsal fin, highly marbled, for sushi.');
